var expect = require('expect.js');
var RuleAdd = require('../../res/page/ruleadd/ruleadd');

describe('sqlscan-ruleadd', function(){
  this.timeout(5000);
  before(function(){
    require('./mock-dev-env').mock();
  });
  after(function(){
    require('./mock-dev-env').unmock();
  });
  describe('#init ruleadd()', function(){
    it('init ruleadd', function(done){
      var ruleadd = RuleAdd._create({
        router : {},
        events : {
          'aftercomplete' : function(){
            expect(ruleadd).to.be.ok();
            var rulename = this.query('combobox[name="rulename"]');
            expect(rulename).to.be.ok();
            var resourceInput = $('#sqlScanResourceId');
            expect(resourceInput).to.be.ok();
            var btnSource = this.query('button[name="btnSource"]');
            expect(btnSource).to.be.ok();
            var btnCreate = this.query('button[name="btnCreate"]');
            expect(btnCreate).to.be.ok();
            var ruledesc = this.query('textareafield[name="ruledesc"]');
            expect(ruledesc).to.be.ok();
            var btnAdd = this.query('button[name="btnAdd"]');
            expect(btnAdd).to.be.ok();
            var btnCancel = this.query('button[name="btnCancel"]');
            expect(btnCancel).to.be.ok();
            done();
          }
        }
      });
    });
  });
  describe('#resource Event', function(){
    it('ResourceEvent', function(done){
      var ruleadd = RuleAdd._create({
        router : {},
        events : {
          'aftercomplete' : function(){
            expect(ruleadd).to.be.ok();
            var btnSource = this.query('button[name="btnSource"]');
            expect(btnSource).to.be.ok();
            btnSource.emit('click');
            var btnCreate = this.query('button[name="btnCreate"]');
            expect(btnCreate).to.be.ok();
            btnCreate.emit('click');
            done();
          },
          'showselectresourcewin' : function(){
            var btnSearch = this.query('button[name="btnSearch"]');
            expect(btnSearch).to.be.ok();
            var sourcelist = this.query('list[name="sourcelist"]');
            expect(sourcelist).to.be.ok();
          },
          'showcreateresourcewin' : function(){
            var scriptName = this.query('field[name="scriptName"]');
            expect(scriptName).to.be.ok();
            var scriptDesc = this.query('textareafield[name="scriptDesc"]');
            expect(scriptDesc).to.be.ok();
          }
        }
      });
    });
  });
  describe('#RuleEvent Event', function(){
    it('RuleEvent', function(done){
      var ruleadd = RuleAdd._create({
        router : {},
        events : {
          'aftercomplete' : function(){
            expect(ruleadd).to.be.ok();
            var btnAddAuthorize = this.query('button[name="btnAddAuthorize"]');
            expect(btnAddAuthorize).to.be.ok();
            expect(this.auhtorItems).to.be(0);
            btnAddAuthorize.emit('click');
            expect(this.auhtorItems).to.be(1);
            btnAddAuthorize.emit('click');
            expect(this.auhtorItems).to.be(2);
            btnAddAuthorize.emit('click');
            expect(this.auhtorItems).to.be(3);
            done();
          }
        }
      });
    });
  });
  describe('#AddEvent Event', function(){
    it('AddEvent', function(done){
      var ruleadd = RuleAdd._create({
        router : {},
        events : {
          'aftercomplete' : function(){
            expect(ruleadd).to.be.ok();
            var btnAdd = this.query('button[name=btnAdd]');
            btnAdd.emit('click');
            expect(this.testCheckValue).to.be('参数不正确');
            var name = this.query('field[name=rulename]');
            var desc = this.query('textareafield[name=ruledesc]');
            name.val('autotest');
            desc.val('test')
            btnAdd.emit('click');
            expect(this.testCheckValue).to.be('资源不能为空');
            var resource = $('#sqlScanResourceId');
            resource.attr("resourceId", 11111);
            this.resourceIdTest = true;
            btnAdd.emit('click');
            var btnCancel = this.query('button[name=btnCancel]');
            btnCancel.emit('click');
            expect(this.testCheckValue).to.be('#controller:rulemanage');
            done();
          },
          'addrulesucess' : function(){
            expect(this.testCheckValue).to.be('规则添加成功');
          }
        }
      });
    });
  });
  describe('#init ruleupdate()', function(){
    it('init ruleupdate', function(done){
      var mockRuleInfo = {
          "users":[{
            "projectRealName":"SYSTEM",
            "user":[{
              "userName":"*",
              "realName":"*"
            }],
            "projectName":"autotest_dev"
          }],
          "ruleBean":{
            "id":1,
            "detail":"test3",
            "resourceId":1,
            "rank":2,
            "name":"test4"
          }
      };
      var ruleadd = RuleAdd._create({
        router : {
          ruleInfo : JSON.stringify(mockRuleInfo)
        },
        events : {
          'aftercomplete' : function(){
            expect(ruleadd).to.be.ok();
            var rulename = this.query('field[name="rulename"]');
            expect(rulename).to.be.ok();
            expect(rulename.val()).to.be('test4');
            var resourceInput = $('#sqlScanResourceId');
            expect(resourceInput).to.be.ok();
            var ruledesc = this.query('textareafield[name="ruledesc"]');
            expect(ruledesc).to.be.ok();
            expect(ruledesc.val()).to.be('test3');
            var apps = this.query('combobox[name=appId]');
            var owners = this.query('combobox[name=owner]');
            owners[0].val('*');
            this.resourceIdTest = true;
            var btnAdd = this.query('button[name=btnAdd]');
            btnAdd.emit('click');
            done();
          },
          'addrulesucess' : function(){
            expect(this.testCheckValue).to.be('规则编辑成功');
          }
        }
      });
    });
  });
});